<?php $adminTitle='Create Course'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST' && verify_csrf($_POST['csrf_token']??null)){ $slug=trim($_POST['slug']) ?: slugify($_POST['title']); $stmt=$pdo->prepare('INSERT INTO lms_courses (category_id,title,slug,short_description,full_description,level,duration,instructor,thumbnail_image,price_type,price,status,learning_outcomes,requirements,target_audience) VALUES (:cat,:title,:slug,:short,:full,:level,:duration,:instructor,:thumb,:ptype,:price,:status,:outcomes,:req,:aud)'); $stmt->execute([':cat'=>(int)$_POST['category_id'],':title'=>trim($_POST['title']),':slug'=>$slug,':short'=>trim($_POST['short_description']),':full'=>trim($_POST['full_description']),':level'=>$_POST['level'],':duration'=>trim($_POST['duration']),':instructor'=>trim($_POST['instructor']),':thumb'=>trim($_POST['thumbnail_image']),':ptype'=>$_POST['price_type'],':price'=>(float)$_POST['price'],':status'=>$_POST['status'],':outcomes'=>trim($_POST['learning_outcomes']),':req'=>trim($_POST['requirements']),':aud'=>trim($_POST['target_audience'])]); header('Location: lms-courses.php'); exit; } ?><h1>Create Course</h1><?php include __DIR__.'/_lms-course-form.php'; include __DIR__.'/../includes/admin-footer.php'; ?>